public class LocalFileSystem implements FileSystem { private static Logger log = LoggerFactory . getLogger ( LocalFileSystem . class ) ; private File root ; private HandleMonitor monitor ; public LocalFileSystem ( ) { } public String getPath ( ) { if ( root != null ) { return root . getPath ( ) ; } else { return null ; } } public void setPath ( String rootPath ) { setRoot ( new File ( osPath ( rootPath ) ) ) ; } public void setRoot ( File root ) { this . root = root ; } public void setEnableHandleMonitor ( String enable ) { setEnableHandleMonitor ( Boolean . valueOf ( enable ) . booleanValue ( ) ) ; } public void setEnableHandleMonitor ( boolean enable ) { if ( enable && monitor == null ) { monitor = new HandleMonitor ( ) ; } if ( ! enable && monitor != null ) { monitor = null ; } } public String getEnableHandleMonitor ( ) { return monitor == null ? "false" : "true" ; } private String osPath ( String genericPath ) { if ( File . separator . equals ( SEPARATOR ) ) { return genericPath ; } return genericPath . replace ( SEPARATOR_CHAR , File . separatorChar ) ; } public boolean equals ( Object obj ) { if ( this == obj ) { return true ; } if ( obj instanceof LocalFileSystem ) { LocalFileSystem other = ( LocalFileSystem ) obj ; if ( root == null ) { return other . root == null ; } else { return root . equals ( other . root ) ; } } return false ; } public int hashCode ( ) { return 0 ; } public void init ( ) throws FileSystemException { if ( root == null ) { String msg = "root directory not set" ; log . debug ( msg ) ; throw new FileSystemException ( msg ) ; } if ( root . exists ( ) ) { if ( ! root . isDirectory ( ) ) { String msg = "path does not denote a folder" ; log . debug ( msg ) ; throw new FileSystemException ( msg ) ; } } else { if ( ! root . mkdirs ( ) ) { String msg = "failed to create root" ; log . debug ( msg ) ; throw new FileSystemException ( msg ) ; } } log . info ( "LocalFileSystem initialized at path " + root . getPath ( ) ) ; if ( monitor != null ) { log . info ( "LocalFileSystem using handle monitor" ) ; } } public void close ( ) throws FileSystemException { root = null ; } public void createFolder ( String folderPath ) throws FileSystemException { File f = new File ( root , osPath ( folderPath ) ) ; if ( f . exists ( ) ) { String msg = f . getPath ( ) + " already exists" ; log . debug ( msg ) ; throw new FileSystemException ( msg ) ; } if ( ! f . mkdirs ( ) ) { String msg = "failed to create folder " + f . getPath ( ) ; log . debug ( msg ) ; throw new FileSystemException ( msg ) ; } } public void deleteFile ( String filePath ) throws FileSystemException { File f = new File ( root , osPath ( filePath ) ) ; if ( ! f . isFile ( ) ) { String msg = f . getPath ( ) + " does not denote an existing file" ; throw new FileSystemException ( msg ) ; } try { FileUtil . delete ( f ) ; } catch ( IOException ioe ) { String msg = "failed to delete " + f . getPath ( ) ; if ( monitor != null && monitor . isOpen ( f ) ) { log . error ( "Unable to delete. There are still open streams." ) ; monitor . dump ( f ) ; } throw new FileSystemException ( msg , ioe ) ; } } public void deleteFolder ( String folderPath ) throws FileSystemException { File f = new File ( root , osPath ( folderPath ) ) ; if ( ! f . isDirectory ( ) ) { String msg = f . getPath ( ) + " does not denote an existing folder" ; log . debug ( msg ) ; throw new FileSystemException ( msg ) ; } try { FileUtil . delete ( f ) ; } catch ( IOException ioe ) { String msg = "failed to delete " + f . getPath ( ) ; log . debug ( msg ) ; throw new FileSystemException ( msg , ioe ) ; } } public boolean exists ( String path ) throws FileSystemException { File f = new File ( root , osPath ( path ) ) ; return f . exists ( ) ; } public InputStream getInputStream ( String filePath ) throws FileSystemException { File f = new File ( root , osPath ( filePath ) ) ; try { if ( monitor == null ) { return new LazyFileInputStream ( f ) ; } else { return monitor . open ( f ) ; } } catch ( FileNotFoundException fnfe ) { String msg = f . getPath ( ) + " does not denote an existing file" ; log . debug ( msg ) ; throw new FileSystemException ( msg , fnfe ) ; } } public OutputStream getOutputStream ( String filePath ) throws FileSystemException { File f = new File ( root , osPath ( filePath ) ) ; try { return new FileOutputStream ( f ) ; } catch ( FileNotFoundException fnfe ) { String msg = "failed to get output stream for " + f . getPath ( ) ; log . debug ( msg ) ; throw new FileSystemException ( msg , fnfe ) ; } } public boolean hasChildren ( String path ) throws FileSystemException { File f = new File ( root , osPath ( path ) ) ; if ( ! f . exists ( ) ) { String msg = f . getPath ( ) + " does not exist" ; log . debug ( msg ) ; throw new FileSystemException ( msg ) ; } if ( f . isFile ( ) ) { return false ; } return ( f . list ( ) . length > 0 ) ; } public boolean isFile ( String path ) throws FileSystemException { File f = new File ( root , osPath ( path ) ) ; return f . isFile ( ) ; } public boolean isFolder ( String path ) throws FileSystemException { File f = new File ( root , osPath ( path ) ) ; return f . isDirectory ( ) ; } public long lastModified ( String path ) throws FileSystemException { File f = new File ( root , osPath ( path ) ) ; return f . lastModified ( ) ; } public long length ( String filePath ) throws FileSystemException { File f = new File ( root , osPath ( filePath ) ) ; if ( ! f . exists ( ) ) { return - 1 ; } return f . length ( ) ; } public String [ ] list ( String folderPath ) throws FileSystemException { File f = new File ( root , osPath ( folderPath ) ) ; String [ ] entries = f . list ( ) ; if ( entries == null ) { String msg = folderPath + " does not denote a folder" ; log . debug ( msg ) ; throw new FileSystemException ( msg ) ; } return entries ; } public String [ ] listFiles ( String folderPath ) throws FileSystemException { File folder = new File ( root , osPath ( folderPath ) ) ; File [ ] files = folder . listFiles ( new FileFilter ( ) { public boolean accept ( File f ) { return f . isFile ( ) ; } } ) ; if ( files == null ) { String msg = folderPath + " does not denote a folder" ; log . debug ( msg ) ; throw new FileSystemException ( msg ) ; } String [ ] entries = new String [ files . length ] ; for ( int i = 0 ; i < files . length ; i ++ ) { entries [ i ] = files [ i ] . getName ( ) ; } return entries ; } public String [ ] listFolders ( String folderPath ) throws FileSystemException { File file = new File ( root , osPath ( folderPath ) ) ; File [ ] folders = file . listFiles ( new FileFilter ( ) { public boolean accept ( File f ) { return f . isDirectory ( ) ; } } ) ; if ( folders == null ) { String msg = folderPath + " does not denote a folder" ; log . debug ( msg ) ; throw new FileSystemException ( msg ) ; } String [ ] entries = new String [ folders . length ] ; for ( int i = 0 ; i < folders . length ; i ++ ) { entries [ i ] = folders [ i ] . getName ( ) ; } return entries ; } }